import React,{useState} from "react";
import axios from "axios";
export default function(){
const[r,set]=useState("");const[d,sd]=useState([]);
function f(){axios.get("http://localhost:5000/student/"+r).then(x=>sd(x.data));}
return(<div className="box">
<input placeholder="Roll" onChange={e=>set(e.target.value)}/>
<button onClick={f}>Search</button>
{d.map(x=>(<div key={x.roll}>
<p>{x.name}</p><p>{x.overall}</p><p>{x.performance}</p>
</div>))}
</div>);}
